259	std::vector<common_chat_msg> common_chat_msgs_parse_oaicompat(const json & messages) {
260	    std::vector<common_chat_msg> msgs;
261	
262	    try {
263	        if (!messages.is_array()) {
264	            throw std::invalid_argument("Expected 'messages' to be an array, got " + messages.dump());
265	        }
266	
267	        for (const auto & message : messages) {
268	            if (!message.is_object()) {
269	                throw std::invalid_argument("Expected 'message' to be an object, got " + message.dump());
270	            }
271	
272	            common_chat_msg msg;
273	            if (!message.contains("role")) {
274	                throw std::invalid_argument("Missing 'role' in message: " + message.dump());
275	            }
276	            msg.role = message.at("role");
277	
278	            auto has_content    = message.contains("content");
279	            auto has_tool_calls = message.contains("tool_calls");
280	            if (has_content) {
281	                const auto & content = message.at("content");
282	                if (content.is_string()) {
283	                    msg.content = content;
284	                } else if (content.is_array()) {
285	                    for (const auto & part : content) {
286	                        if (!part.contains("type")) {
287	                            throw std::invalid_argument("Missing content part type: " + part.dump());
288	                        }
289	                        const auto & type = part.at("type");
290	                        if (type != "text" && type != "media_marker") {
291	                            throw std::invalid_argument("Unsupported content part type: " + type.dump());
292	                        }
293	                        common_chat_msg_content_part msg_part;
294	                        msg_part.type = type;
295	                        msg_part.text = part.at("text");
296	                        msg.content_parts.push_back(msg_part);
297	                    }
298	                } else if (!content.is_null()) {
299	                    throw std::invalid_argument("Invalid 'content' type: expected string or array, got " +
300	                                                content.dump() +
301	                                                " (ref: https://github.com/ggml-org/llama.cpp/issues/8367)");
302	                }
303	            }
304	            if (has_tool_calls) {
305	                for (const auto & tool_call : message.at("tool_calls")) {
306	                    common_chat_tool_call tc;
307	                    if (!tool_call.contains("type")) {
308	                        throw std::invalid_argument("Missing tool call type: " + tool_call.dump());
309	                    }
310	                    const auto & type = tool_call.at("type");
311	                    if (type != "function") {
312	                        throw std::invalid_argument("Unsupported tool call type: " + tool_call.dump());
313	                    }
314	                    if (!tool_call.contains("function")) {
315	                        throw std::invalid_argument("Missing tool call function: " + tool_call.dump());
316	                    }
317	                    const auto & fc = tool_call.at("function");
318	                    if (!fc.contains("name")) {
319	                        throw std::invalid_argument("Missing tool call name: " + tool_call.dump());
320	                    }
321	                    tc.name           = fc.at("name");
322	                    const auto & args = fc.at("arguments");

825	static common_chat_params common_chat_params_init_ministral_3(const common_chat_template &    tmpl,
826	                                                              const autoparser::generation_params & inputs) {
827	    common_chat_params data;
828	
829	    // Build up messages to follow the format: https://huggingface.co/mistralai/Ministral-3-14B-Reasoning-2512/blob/main/chat_template.jinja
830	    auto adjusted_messages = json::array();
831	    for (const auto & msg : inputs.messages) {
832	        auto role = msg.value("role", "");
833	        if (role != "system" && role != "assistant") {
834	            // Only adjust system and assistant messages. Interestingly, the system message may contain thinking.
835	            adjusted_messages.push_back(msg);
836	            continue;
837	        }
838	
839	        auto content = json::array();
840	
841	        // If message contains `reasoning_content`, add it as a block of type `thinking`
842	        if (msg.contains("reasoning_content") && msg.at("reasoning_content").is_string()) {
843	            content.push_back({
844	                { "type",     "thinking"                                     },
845	                { "thinking", msg.at("reasoning_content").get<std::string>() },
846	            });
847	        }
848	
849	        // If message contains `content`, add it as a block of type `text`
850	        if (msg.contains("content")) {
851	            if (msg.at("content").is_string()) {
852	                content.push_back({
853	                    { "type", "text"                               },
854	                    { "text", msg.at("content").get<std::string>() },
855	                });
856	            } else if (msg.at("content").is_array()) {
857	                auto blocks = msg.at("content");
858	                content.insert(content.end(), blocks.begin(), blocks.end());
859	            }
860	        }
861	
862	        auto adjusted       = msg;
863	        adjusted["content"] = content;
864	        adjusted.erase("reasoning_content");
865	        adjusted_messages.push_back(adjusted);
866	    }
867	
868	    auto has_tools         = inputs.tools.is_array() && !inputs.tools.empty();
869	    auto extract_reasoning = inputs.reasoning_format != COMMON_REASONING_FORMAT_NONE;
870	    auto include_grammar   = true;
871	
872	    data.supports_thinking  = true;
873	    data.thinking_start_tag = "[THINK]";
874	    data.thinking_end_tag   = "[/THINK]";
875	    data.prompt            = common_chat_template_direct_apply_impl(tmpl, inputs, /* messages_override = */ adjusted_messages);
876	    data.format            = COMMON_CHAT_FORMAT_PEG_NATIVE;
877	    data.preserved_tokens  = {
878	        "[THINK]",
879	        "[/THINK]",
880	        "[TOOL_CALLS]",
881	        "[ARGS]",
882	    };
883	
884	    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
885	        auto generation_prompt = p.prefix(inputs.generation_prompt, "[THINK]");
886	        auto reasoning =
887	            extract_reasoning ? p.optional("[THINK]" + p.reasoning(p.until("[/THINK]")) + "[/THINK]") : p.eps();
888	
889	        // Response format parser
890	        if (inputs.json_schema.is_object() && !inputs.json_schema.empty()) {
891	            // Ministral wants to emit json surrounded by code fences
